import { z } from 'zod';

export const customerSchema = z.object({
  name: z.string().min(3, { message: "Name must be at least 3 characters long." }),
  email: z.string().email({ message: "Please enter a valid email address." }),
  phone: z.string().regex(/^\+254\d{9}$/, { message: "Phone must be in the format +2547XXXXXXXX." }),
  address: z.string().min(10, { message: "Address must be at least 10 characters long." }),
});

export type CustomerFormData = z.infer<typeof customerSchema>;

export const readingSchema = z.object({
    reading: z.coerce.number().min(0, { message: "Reading must be a non-negative number." }),
    date: z.string().min(1, { message: "Date is required." }),
});

export type ReadingFormData = z.infer<typeof readingSchema>;

const baseMeterSchema = z.object({
  serialNumber: z.string().min(5, { message: "Serial number must be at least 5 characters." }),
  customerAccount: z.string().optional().nullable(),
  installationDate: z.string()
    .refine((date) => !isNaN(Date.parse(date)), { message: "Invalid date format." })
    .refine((date) => new Date(date) <= new Date(), { message: "Installation date cannot be in the future." }),
});

export const addMeterSchema = baseMeterSchema.extend({
    initialReading: z.coerce.number().min(0, { message: "Initial reading must be non-negative." }),
});

export const editMeterSchema = baseMeterSchema;

export type AddMeterFormData = z.infer<typeof addMeterSchema>;
export type EditMeterFormData = z.infer<typeof editMeterSchema>;

export const createInvoiceSchema = z.object({
  customerId: z.string().min(1, { message: "A customer must be selected." }),
  issueDate: z.string().min(1, { message: "Issue date is required." }),
  dueDate: z.string().min(1, { message: "Due date is required." }),
  items: z.array(z.object({
    description: z.string().min(3, { message: "Description must be at least 3 characters." }),
    quantity: z.coerce.number().min(0.01, { message: "Quantity must be positive." }),
    unitPrice: z.coerce.number().min(0, { message: "Unit price must be non-negative." }),
  })).min(1, { message: "At least one item is required." }),
}).refine(data => new Date(data.dueDate) >= new Date(data.issueDate), {
  message: "Due date cannot be before the issue date.",
  path: ["dueDate"],
});

export type CreateInvoiceFormData = z.infer<typeof createInvoiceSchema>;

export const recordPaymentSchema = z.object({
  customerId: z.string().min(1, { message: "A customer must be selected." }),
  invoiceId: z.string().min(1, { message: "An invoice must be selected." }),
  amount: z.coerce.number().positive({ message: "Amount must be a positive number." }),
  method: z.enum(['M-Pesa', 'Cash', 'Bank'], { required_error: "Payment method is required." }),
  date: z.string().min(1, { message: "Payment date is required." }),
});

export type RecordPaymentFormData = z.infer<typeof recordPaymentSchema>;

export const userSchema = z.object({
  name: z.string().min(3, { message: "Full name must be at least 3 characters." }),
  email: z.string().email({ message: "Please enter a valid email address." }),
  role: z.enum(['Admin', 'Manager', 'Agent'], { required_error: "Role is required." }),
});

export type UserFormData = z.infer<typeof userSchema>;

const express = require('express');
const cors = require('cors');
const db = require('./db');
const path = require('path');
const fs = require('fs');

const app = express();
const PORT = 3001;

app.use(cors());
app.use(express.json());

// --- DASHBOARD ---
app.get('/api/dashboard', (req, res) => {
    try {
        const totalBilled = db.prepare("SELECT SUM(total) as value FROM invoices WHERE issueDate >= date('now', '-30 days')").get().value || 0;
        const totalCollected = db.prepare("SELECT SUM(amount) as value FROM payments WHERE date >= date('now', '-30 days')").get().value || 0;
        const activeCustomers = db.prepare("SELECT count(*) as value FROM customers").get().value || 0;
        const overdueAccounts = db.prepare("SELECT count(*) as value FROM invoices WHERE status = 'Overdue'").get().value || 0;

        const revenueData = db.prepare(`
            WITH RECURSIVE months(m) AS (
                SELECT date('now', 'start of month')
                UNION ALL
                SELECT date(m, '-1 month') FROM months WHERE m > date('now', 'start of month', '-5 months')
            )
            SELECT
                strftime('%b', m) as month,
                (SELECT IFNULL(SUM(total), 0) FROM invoices WHERE strftime('%Y-%m', issueDate) = strftime('%Y-%m', m)) as billed,
                (SELECT IFNULL(SUM(amount), 0) FROM payments WHERE strftime('%Y-%m', date) = strftime('%Y-%m', m)) as collected
            FROM months ORDER BY m ASC
        `).all();

        const agingData = [
            { name: '0-30 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Due' AND dueDate >= date('now', '-30 days')").get().v || 0, fill: '#3b82f6' },
            { name: '31-60 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Overdue' AND dueDate BETWEEN date('now', '-60 days') AND date('now', '-31 days')").get().v || 0, fill: '#f59e0b' },
            { name: '61-90 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Overdue' AND dueDate BETWEEN date('now', '-90 days') AND date('now', '-61 days')").get().v || 0, fill: '#ef4444' },
            { name: '90+ Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Overdue' AND dueDate < date('now', '-90 days')").get().v || 0, fill: '#7f1d1d' },
        ];

        const defaulters = db.prepare("SELECT id, customerName as name, customerAccount as account, total as amountDue, CAST(julianday('now') - julianday(dueDate) AS INTEGER) as daysOverdue FROM invoices WHERE status = 'Overdue' ORDER BY amountDue DESC LIMIT 5").all();
        const recentPayments = db.prepare("SELECT * FROM payments ORDER BY date DESC LIMIT 4").all();

        res.json({
            kpiData: [
                { title: 'Total Billed (Month)', value: `KES ${totalBilled.toLocaleString()}`, change: '+5.2%', changeType: 'increase' },
                { title: 'Total Collected (Month)', value: `KES ${totalCollected.toLocaleString()}`, change: '+8.1%', changeType: 'increase' },
                { title: 'Active Customers', value: activeCustomers.toLocaleString(), change: '+25', changeType: 'increase' },
                { title: 'Overdue Accounts', value: overdueAccounts.toLocaleString(), change: '-3.4%', changeType: 'decrease' },
            ],
            revenueData,
            agingData,
            defaulters,
            recentPayments,
            nrwData: [
                { day: 'Mon', percentage: 18.5 }, { day: 'Tue', percentage: 19.2 }, { day: 'Wed', percentage: 17.8 },
                { day: 'Thu', percentage: 20.1 }, { day: 'Fri', percentage: 19.5 }, { day: 'Sat', percentage: 21.3 }, { day: 'Sun', percentage: 20.8 },
            ]
        });
    } catch (error) {
        res.status(500).json({ message: 'Failed to fetch dashboard data', error: error.message });
    }
});

// --- CUSTOMERS ---
app.get('/api/customers', (req, res) => {
    try {
        const { q, sortKey, sortDir, page = 1, limit = 10 } = req.query;
        let query = 'SELECT * FROM customers';
        const params = [];
        if (q) {
            query += ' WHERE name LIKE ? OR accountNumber LIKE ? OR email LIKE ?';
            params.push(`%${q}%`, `%${q}%`, `%${q}%`);
        }
        if (sortKey && sortDir) {
            query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
        } else {
             query += ` ORDER BY joinDate DESC`;
        }
        const totalItemsQuery = q 
            ? 'SELECT COUNT(*) as count FROM customers WHERE name LIKE ? OR accountNumber LIKE ? OR email LIKE ?'
            : 'SELECT COUNT(*) as count FROM customers';
        const totalItems = db.prepare(totalItemsQuery).get(q ? [`%${q}%`, `%${q}%`, `%${q}%`] : []).count;

        if (limit !== 'all') {
            const parsedLimit = parseInt(limit) || 10;
            const parsedPage = parseInt(page) || 1;
            query += ' LIMIT ? OFFSET ?';
            params.push(parsedLimit, (parsedPage - 1) * parsedLimit);
        }
        const customers = db.prepare(query).all(...params);
        res.json({ customers, totalItems });
    } catch (error) {
        res.status(500).json({ message: 'Failed to fetch customers', error: error.message });
    }
});

app.get('/api/customers/:id', (req, res) => {
    try {
        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(req.params.id);
        if (!customer) return res.status(404).json({ message: 'Customer not found' });
        const invoices = db.prepare('SELECT * FROM invoices WHERE customerAccount = ? ORDER BY issueDate DESC').all(customer.accountNumber);
        const payments = db.prepare('SELECT * FROM payments WHERE customerName = ? ORDER BY date DESC').all(customer.name);
        const meters = db.prepare('SELECT * FROM meters WHERE customerAccount = ?').all(customer.accountNumber);
        const outstandingBalance = db.prepare("SELECT SUM(total) as totalDue FROM invoices WHERE customerAccount = ? AND status IN ('Due', 'Overdue')").get(customer.accountNumber).totalDue || 0;
        res.json({ customer, history: { invoices, payments }, meters, outstandingBalance, lastUpdated: new Date().toISOString() });
    } catch (err) {
        res.status(500).json({ message: 'Failed to fetch customer profile', error: err.message });
    }
});

app.post('/api/customers', (req, res) => {
    try {
        const { name, email, phone, address } = req.body;
        const last = db.prepare("SELECT id FROM customers ORDER BY id DESC LIMIT 1").get();
        const nextIdNum = last ? parseInt(last.id.split('-')[1]) + 1 : 1001;
        const id = `CUST-${nextIdNum}`;
        const acc = `ACC-${20000 + nextIdNum}`;
        db.prepare('INSERT INTO customers (id, accountNumber, name, email, phone, address, joinDate) VALUES (?, ?, ?, ?, ?, ?, ?)')
          .run(id, acc, name, email, phone, address, new Date().toISOString().split('T')[0]);
        res.status(201).json({ id, accountNumber: acc });
    } catch (err) {
        res.status(500).json({ message: 'Failed to create customer', error: err.message });
    }
});

app.put('/api/customers/:id', (req, res) => {
    try {
        const { name, email, phone, address } = req.body;
        db.prepare('UPDATE customers SET name = ?, email = ?, phone = ?, address = ? WHERE id = ?').run(name, email, phone, address, req.params.id);
        res.json({ message: 'Updated' });
    } catch (err) {
        res.status(500).json({ message: 'Update failed', error: err.message });
    }
});

// --- METERS ---
app.get('/api/meters', (req, res) => {
    try {
        const { q, status } = req.query;
        let query = 'SELECT * FROM meters';
        const params = [];
        if (q || (status && status !== 'all')) {
            query += ' WHERE ';
            const parts = [];
            if (q) { parts.push('(serialNumber LIKE ? OR customerAccount LIKE ?)'); params.push(`%${q}%`, `%${q}%`); }
            if (status && status !== 'all') { parts.push('status = ?'); params.push(status); }
            query += parts.join(' AND ');
        }
        const meters = db.prepare(query).all(...params);
        const readings = db.prepare('SELECT * FROM meter_readings').all();
        const history = db.prepare('SELECT * FROM meter_status_history').all();
        res.json({ meters, readings, history });
    } catch (error) {
        res.status(500).json({ message: 'Meter fetch error', error: error.message });
    }
});

app.post('/api/meters', (req, res) => {
    const { serialNumber, customerAccount, installationDate, initialReading } = req.body;
    const mid = `M-${Date.now()}`;
    try {
        db.transaction(() => {
            db.prepare('INSERT INTO meters (id, serialNumber, customerAccount, status, installationDate) VALUES (?, ?, ?, ?, ?)')
              .run(mid, serialNumber, customerAccount || null, 'Active', installationDate);
            db.prepare('INSERT INTO meter_readings (id, meterId, reading, date) VALUES (?, ?, ?, ?)')
              .run(`R-${Date.now()}`, mid, initialReading, installationDate);
        })();
        res.status(201).json({ id: mid });
    } catch (err) {
        res.status(500).json({ message: 'Failed to add meter', error: err.message });
    }
});

app.post('/api/meters/:id/readings', (req, res) => {
    const { reading, date } = req.body;
    try {
        db.prepare('INSERT INTO meter_readings (id, meterId, reading, date) VALUES (?, ?, ?, ?)')
          .run(`R-${Date.now()}`, req.params.id, reading, date);
        res.status(201).json({ success: true });
    } catch (err) {
        res.status(500).json({ message: 'Failed to add reading', error: err.message });
    }
});

// --- INVOICES ---
app.get('/api/invoices', (req, res) => {
    try {
        const { q, sortKey, sortDir, page = 1, limit = 10, status } = req.query;
        let query = 'SELECT * FROM invoices';
        const params = [];
        const cond = [];
        if (q) { cond.push('(id LIKE ? OR customerName LIKE ? OR customerAccount LIKE ?)'); params.push(`%${q}%`, `%${q}%`, `%${q}%`); }
        if (status) { const list = status.split(','); cond.push(`status IN (${list.map(()=>'?').join(',')})`); params.push(...list); }
        if (cond.length) query += ' WHERE ' + cond.join(' AND ');
        if (sortKey) query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
        else query += ' ORDER BY issueDate DESC';

        const totalItems = db.prepare(query.replace('SELECT *', 'SELECT COUNT(*) as count')).get(...params).count;
        if (limit !== 'all') {
            const l = parseInt(limit) || 10;
            query += ' LIMIT ? OFFSET ?';
            params.push(l, (parseInt(page)-1)*l);
        }
        const invs = db.prepare(query).all(...params);
        const itemStmt = db.prepare('SELECT * FROM invoice_items WHERE invoiceId = ?');
        res.json({ invoices: invs.map(i => ({...i, items: itemStmt.all(i.id)})), totalItems });
    } catch (error) {
        res.status(500).json({ message: 'Invoice fetch error', error: error.message });
    }
});

app.get('/api/invoices/bulk/preview', (req, res) => {
    try {
        const preview = db.prepare(`
            SELECT c.id as customerId, c.name, c.accountNumber, c.address, m.id as meterId, m.serialNumber,
                   (SELECT reading FROM meter_readings WHERE meterId = m.id ORDER BY date DESC LIMIT 1) as currentReading,
                   (SELECT MAX(issueDate) FROM invoices WHERE customerAccount = c.accountNumber) as lastInvoiceDate
            FROM customers c JOIN meters m ON m.customerAccount = c.accountNumber
        `).all().map(item => {
            const r = item.lastInvoiceDate 
                ? db.prepare("SELECT reading FROM meter_readings WHERE meterId = ? AND date <= ? ORDER BY date DESC LIMIT 1").get(item.meterId, item.lastInvoiceDate)
                : db.prepare("SELECT reading FROM meter_readings WHERE meterId = ? ORDER BY date ASC LIMIT 1").get(item.meterId);
            const prev = r ? r.reading : 0;
            const cons = Math.max(0, item.currentReading - prev);
            return { ...item, previousReading: prev, consumption: cons, total: cons * 110 + 350 };
        });
        res.json(preview);
    } catch (err) {
        res.status(500).json({ message: 'Preview failed', error: err.message });
    }
});

app.post('/api/invoices/bulk/generate', (req, res) => {
    const { batch, issueDate, dueDate, unitPrice = 110 } = req.body;
    try {
        db.transaction(() => {
            for (const item of batch) {
                const last = db.prepare("SELECT id FROM invoices ORDER BY id DESC LIMIT 1").get();
                const nextId = last ? parseInt(last.id.split('-')[2]) + 1 : 1001;
                const id = `INV-${new Date().getFullYear()}-${nextId}`;
                const total = item.consumption * unitPrice + 350;
                db.prepare('INSERT INTO invoices (id, customerName, customerAccount, customerAddress, issueDate, generationDate, dueDate, subtotal, penalties, total, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)')
                  .run(id, item.name, item.accountNumber, item.address, issueDate, new Date().toISOString().split('T')[0], dueDate, total, 0, total, 'Due');
                db.prepare('INSERT INTO invoice_items (invoiceId, description, quantity, unitPrice, total) VALUES (?, ?, ?, ?, ?)')
                  .run(id, `Water Usage`, item.consumption, unitPrice, item.consumption * unitPrice);
            }
        })();
        res.json({ success: true });
    } catch (err) {
        res.status(500).json({ message: 'Bulk gen failed', error: err.message });
    }
});

app.post('/api/invoices/:id/pay', (req, res) => {
    try {
        const inv = db.prepare('SELECT * FROM invoices WHERE id = ?').get(req.params.id);
        if (!inv) return res.status(404).json({ message: 'Not found' });
        db.transaction(() => {
            db.prepare('UPDATE invoices SET status = "Paid" WHERE id = ?').run(req.params.id);
            db.prepare('INSERT INTO payments (id, customerName, amount, method, date, invoiceId) VALUES (?, ?, ?, ?, ?, ?)')
              .run(`RPT-${Date.now()}`, inv.customerName, inv.total, req.body.method || 'Manual', new Date().toISOString().split('T')[0], req.params.id);
        })();
        res.json({ success: true });
    } catch (err) {
        res.status(500).json({ message: 'Payment failed', error: err.message });
    }
});

// --- PAYMENTS ---
app.get('/api/payments', (req, res) => {
    const { page = 1, limit = 10, q } = req.query;
    let query = 'SELECT * FROM payments';
    const params = [];
    if (q) { query += ' WHERE customerName LIKE ? OR invoiceId LIKE ?'; params.push(`%${q}%`, `%${q}%`); }
    query += ' ORDER BY date DESC';
    const total = db.prepare(query.replace('SELECT *', 'SELECT COUNT(*) as count')).get(...params).count;
    const l = parseInt(limit);
    query += ' LIMIT ? OFFSET ?';
    params.push(l, (parseInt(page)-1)*l);
    res.json({ payments: db.prepare(query).all(...params), totalItems: total });
});

// --- SETTINGS ---
app.get('/api/settings/billing', (req, res) => res.json(db.prepare('SELECT * FROM billing_settings WHERE id = 1').get()));
app.post('/api/settings/billing', (req, res) => {
    const { frequency, generationDay, readingCutoffDays } = req.body;
    db.prepare('UPDATE billing_settings SET frequency = ?, generationDay = ?, readingCutoffDays = ? WHERE id = 1').run(frequency, generationDay, readingCutoffDays);
    res.json({ success: true });
});

// --- USERS ---
app.get('/api/users', (req, res) => res.json(db.prepare('SELECT * FROM users ORDER BY name ASC').all()));
app.post('/api/users', (req, res) => {
    const { name, email, role } = req.body;
    try {
        db.prepare('INSERT INTO users (id, name, email, role, lastActive) VALUES (?, ?, ?, ?, ?)')
          .run(`USR-${Date.now()}`, name, email, role, new Date().toISOString());
        res.status(201).json({ success: true });
    } catch (err) { res.status(500).json({ message: 'Email already exists' }); }
});

app.delete('/api/users/:id', (req, res) => {
    db.prepare('DELETE FROM users WHERE id = ?').run(req.params.id);
    res.json({ success: true });
});

app.get('/api/db/validate', (req, res) => {
    try {
        const check = db.prepare('PRAGMA integrity_check').get();
        const counts = {
            customers: db.prepare('SELECT count(*) as count FROM customers').get().count,
            meters: db.prepare('SELECT count(*) as count FROM meters').get().count,
            readings: db.prepare('SELECT count(*) as count FROM meter_readings').get().count,
            invoices: db.prepare('SELECT count(*) as count FROM invoices').get().count,
            payments: db.prepare('SELECT count(*) as count FROM payments').get().count,
            users: db.prepare('SELECT count(*) as count FROM users').get().count,
        };
        const f = path.join(__dirname, 'db', 'database.sqlite');
        const size = fs.existsSync(f) ? (fs.statSync(f).size / 1024).toFixed(2) + ' KB' : '0 KB';
        res.json({ status: check.integrity_check === 'ok' ? 'Healthy' : 'Corrupted', integrityMessage: check.integrity_check, tableCounts: counts, size, lastValidated: new Date().toISOString() });
    } catch (err) { res.status(500).json({ message: 'Diag failed', error: err.message }); }
});

app.listen(PORT, () => console.log(`Server is running on http://localhost:${PORT}`));

