                   (SELECT reading FROM meter_readings WHERE meterId = m.id ORDER BY date DESC LIMIT 1) as currentReading,
                   (SELECT MAX(issueDate) FROM invoices WHERE customerAccount = c.accountNumber) as lastInvoiceDate
            FROM customers c JOIN meters m ON m.customerAccount = c.accountNumber
        `).all().map(item => {
            const r = item.lastInvoiceDate 
                ? db.prepare("SELECT reading FROM meter_readings WHERE meterId = ? AND date <= ? ORDER BY date DESC LIMIT 1").get(item.meterId, item.lastInvoiceDate)
                : db.prepare("SELECT reading FROM meter_readings WHERE meterId = ? ORDER BY date ASC LIMIT 1").get(item.meterId);
            const prev = r ? r.reading : 0;
            const cons = Math.max(0, item.currentReading - prev);
            return { ...item, previousReading: prev, consumption: cons, total: cons * 110 + 350 };
        });
        res.json(preview);
    } catch (err) {
        res.status(500).json({ message: 'Preview failed', error: err.message });
    }
});

