            payments: db.prepare('SELECT count(*) as count FROM payments').get().count,
            users: db.prepare('SELECT count(*) as count FROM users').get().count,
        };
        const f = path.join(__dirname, 'db', 'database.sqlite');
        const size = fs.existsSync(f) ? (fs.statSync(f).size / 1024).toFixed(2) + ' KB' : '0 KB';
        res.json({ status: check.integrity_check === 'ok' ? 'Healthy' : 'Corrupted', integrityMessage: check.integrity_check, tableCounts: counts, size, lastValidated: new Date().toISOString() });
    } catch (err) { res.status(500).json({ message: 'Diag failed', error: err.message }); }
});

